from enum import Enum
from plum import dispatch
from typing import TypeVar, Union, Generic, List, Tuple
from spire.pdf.common import *
from spire.pdf import *
from ctypes import *
import abc

class LineBorder(SpireObject):
    """
    Represents the border style of the Line annotation.
    """

    @property
    def BorderWidth(self) -> int:
        """
        Gets or sets the width.
        Returns: The line border width.
        """
        GetDllLibPdf().spr_pdf_LineBorder_get_BorderWidth.argtypes = [c_void_p]
        GetDllLibPdf().spr_pdf_LineBorder_get_BorderWidth.restype = c_int
        ret = CallCFunction(GetDllLibPdf().spr_pdf_LineBorder_get_BorderWidth,self.Ptr)
        return ret

    @BorderWidth.setter
    def BorderWidth(self, value: int):
        """
        Sets the width.
        Args:
            value: The line border width.
        """
        GetDllLibPdf().spr_pdf_LineBorder_set_BorderWidth.argtypes = [c_void_p, c_int]
        CallCFunction(GetDllLibPdf().spr_pdf_LineBorder_set_BorderWidth,self.Ptr, value)

    @property
    def BorderStyle(self) -> 'PdfBorderStyle':
        """
        Gets or sets the border style.
        Returns: The line border style.
        """
        GetDllLibPdf().spr_pdf_LineBorder_get_BorderStyle.argtypes = [c_void_p]
        GetDllLibPdf().spr_pdf_LineBorder_get_BorderStyle.restype = c_int
        ret = CallCFunction(GetDllLibPdf().spr_pdf_LineBorder_get_BorderStyle,self.Ptr)
        objwrapped = PdfBorderStyle(ret)
        return objwrapped

    @BorderStyle.setter
    def BorderStyle(self, value: 'PdfBorderStyle'):
        """
        Sets the border style.
        Args:
            value: The line border style.
        """
        GetDllLibPdf().spr_pdf_LineBorder_set_BorderStyle.argtypes = [c_void_p, c_int]
        CallCFunction(GetDllLibPdf().spr_pdf_LineBorder_set_BorderStyle,self.Ptr, value.value)

    @property
    def DashArray(self) -> int:
        """
        Gets or sets the Line Dash.
        Returns: The line border dash array.
        """
        GetDllLibPdf().spr_pdf_LineBorder_get_DashArray.argtypes = [c_void_p]
        GetDllLibPdf().spr_pdf_LineBorder_get_DashArray.restype = c_int
        ret = CallCFunction(GetDllLibPdf().spr_pdf_LineBorder_get_DashArray,self.Ptr)
        return ret

    @DashArray.setter
    def DashArray(self, value: int):
        """
        Sets the Line Dash.
        Args: value: The line border dash array.
        """
        GetDllLibPdf().spr_pdf_LineBorder_set_DashArray.argtypes = [c_void_p, c_int]
        CallCFunction(GetDllLibPdf().spr_pdf_LineBorder_set_DashArray,self.Ptr, value)